"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[32],{8046:e=>{e.exports=JSON.parse('{"functions":[{"name":"createWorld","desc":"Builds a new [`World`](World). Spins up `config.threads` simulation actors\\n(default 16) under `config.actorContainer`, requires the definitions module\\nin every actor VM, builds the main-thread snapshot store, and returns the\\nhandle.\\n\\n`actorContainer` and `definitionsModule` are required; every other field\\nfalls back to the values on [`Hindsight.Defaults`](Defaults).\\n\\n```lua\\nlocal world = Hindsight.createWorld({\\n    actorContainer    = ServerScriptService,\\n    definitionsModule = ReplicatedStorage.Shared.Definitions,\\n    visualsContainer  = workspace.Bullets,\\n})\\n```","params":[{"name":"config","desc":"","lua_type":"WorldConfig"}],"returns":[{"desc":"","lua_type":"World"}],"function_type":"static","source":{"line":422,"path":"src/World.lua"}}],"properties":[{"name":"Defaults","desc":"Built-in defaults used when the caller omits a config block on\\n[`createWorld`](#createWorld). Useful for debug tooling that wants to\\nintrospect the values the world is actually running with, and as a base to\\nclone-and-edit when you only want to override a few fields.","lua_type":"Defaults","source":{"line":42,"path":"src/init.lua"}}],"types":[{"name":"Extra","desc":"An open table travelling with every projectile. Set on a per-cast basis via\\n[`ProjectileModifier`](#ProjectileModifier).`extra`, surfaced on every\\ncallback\'s `ctx.extra`, and passed to the [`Filter`](#Filter).","lua_type":"{ [string]: any }","source":{"line":51,"path":"src/init.lua"}},{"name":"Caster","desc":"Whatever the game considers the shooter. Players for player weapons; Models\\nfor NPCs, turrets, or vehicles. The reference must resolve identically on\\nevery peer that runs a matching cast.","lua_type":"Player | Model","source":{"line":60,"path":"src/init.lua"}},{"name":"Filter","desc":"Optional per-character hit-skip predicate. Returns `true` to skip the\\ncandidate; `false`/`nil` to accept. Lives on a [`ProjectileDefinition`](#ProjectileDefinition)\\nor is passed directly to [`Rollback:queryRay`](Rollback#queryRay).\\n\\nWhen used by the projectile simulator, runs inside the simulation actor in\\n**parallel context** \u2014 read-only and thread-safe: no instance writes, no\\n`Humanoid` state inspection beyond what\'s already captured.\\n\\nWhen used by a manual [`Rollback:queryRay`](Rollback#queryRay) call, runs on\\nthe main thread.","lua_type":"(caster: Caster, victim: Player?, character: Model, extra: Extra) -> boolean","source":{"line":76,"path":"src/init.lua"}},{"name":"Rig","desc":"Hitbox layout for one rig kind. See [`Defaults.rigs`](Defaults#rigs) for the\\nbuilt-in R15 and R6 entries.","fields":[{"name":"parts","lua_type":"{ string }","desc":"Names of the BaseParts that form this rig\'s hitboxes, indexed in parallel with `sizes`."},{"name":"sizes","lua_type":"{ Vector3 }","desc":"Half-extents of each part\'s OBB, in stud-space. `sizes[i]` is paired with `parts[i]`."}],"source":{"line":86,"path":"src/init.lua"}},{"name":"RollbackConfig","desc":"","fields":[{"name":"lifetime","lua_type":"number","desc":"Seconds of history retained. Older snapshots are dropped on `capture`."},{"name":"voxelSize","lua_type":"number","desc":"Broadphase voxel cell size in studs."},{"name":"gridCenter","lua_type":"Vector3","desc":"World-space center of the voxel space."},{"name":"gridSize","lua_type":"Vector3","desc":"World-space size of the voxel space. Characters outside this AABB are not findable via `queryRay`."},{"name":"hitboxSize","lua_type":"Vector3","desc":"Half-extents used to fatten each character\'s footprint in the voxel grid."},{"name":"rigs","lua_type":"{ [string]: Rig }","desc":"Hitbox layouts, keyed by rig name (e.g. `\\"R15\\"`, `\\"R6\\"`)."}],"source":{"line":97,"path":"src/init.lua"}},{"name":"PenetrationConfig","desc":"","fields":[{"name":"surfaceHardness","lua_type":"{ [Enum.Material]: number }","desc":"Per-material hardness. Unlisted materials use `defaultHardness`."},{"name":"defaultHardness","lua_type":"number","desc":"Fallback hardness for materials not in `surfaceHardness`."},{"name":"ricochetHardness","lua_type":"number","desc":"Minimum hardness for a surface to be eligible to ricochet a projectile."},{"name":"mediumGapThreshold","lua_type":"number","desc":"Gap size in studs below which adjacent parts are merged into one compound medium."},{"name":"maxCompoundMediumParts","lua_type":"number","desc":"Upper bound on parts joined into one compound medium."}],"source":{"line":107,"path":"src/init.lua"}},{"name":"WorldConfig","desc":"The top-level configuration passed to [`createWorld`](#createWorld). Every\\nwiring decision lives here \u2014 the library never looks anything up on its own.","fields":[{"name":"actorContainer","lua_type":"Instance","desc":"Container into which the simulation Actors are parented."},{"name":"definitionsModule","lua_type":"ModuleScript","desc":"ModuleScript returning `{ [string]: ProjectileDefinition }`."},{"name":"visualsContainer","lua_type":"Instance?","desc":"Where bullet visuals get parented on the client. nil on the server."},{"name":"excludeContainers","lua_type":"{ Instance }?","desc":"Descendants are skipped as penetration continuation candidates (e.g. visuals folder, characters folder)."},{"name":"threads","lua_type":"number?","desc":"Number of simulation actors. Defaults to 16."},{"name":"serverFrameRate","lua_type":"number?","desc":"Frame budget for the actor pool. Defaults to 1/60."},{"name":"frameTimeBudget","lua_type":"number?","desc":"Fraction of `serverFrameRate` an actor will spend stepping projectiles per frame. Defaults to 0.5."},{"name":"interpolation","lua_type":"number?","desc":"Client-side replication interpolation delay. Defaults to 0.048."},{"name":"rollback","lua_type":"RollbackConfig?","desc":"Overrides [`Defaults.rollback`](Defaults#rollback)."},{"name":"penetration","lua_type":"PenetrationConfig?","desc":"Overrides [`Defaults.penetration`](Defaults#penetration)."},{"name":"defaultRaycastFilter","lua_type":"RaycastParams?","desc":"Fallback raycast filter used when a definition doesn\'t supply its own."}],"source":{"line":126,"path":"src/init.lua"}},{"name":"ImpactCtx","desc":"Argument to a definition\'s `onImpact` callback. Fired on the main thread\\nafter `task.synchronize()`.","fields":[{"name":"type","lua_type":"string","desc":"Definition key the projectile was cast under."},{"name":"caster","lua_type":"Caster","desc":"Whoever fired the projectile."},{"name":"direction","lua_type":"Vector3","desc":"Velocity at the moment of impact."},{"name":"instance","lua_type":"Instance","desc":"The world part that was hit."},{"name":"normal","lua_type":"Vector3","desc":"Surface normal at the hit point."},{"name":"position","lua_type":"Vector3","desc":"World-space hit point."},{"name":"material","lua_type":"Enum.Material","desc":"Surface material of the hit part."},{"name":"extra","lua_type":"Extra","desc":"Per-cast extra table."}],"source":{"line":142,"path":"src/init.lua"}},{"name":"IntersectionCtx","desc":"Argument to a definition\'s `onIntersection` callback. Fired on the main\\nthread after `task.synchronize()` \u2014 Humanoid state reads are safe here.","fields":[{"name":"type","lua_type":"string","desc":"Definition key the projectile was cast under."},{"name":"caster","lua_type":"Caster","desc":"Whoever fired the projectile."},{"name":"direction","lua_type":"Vector3","desc":"Velocity at the moment of intersection."},{"name":"part","lua_type":"string","desc":"Name of the character part that was hit (e.g. `\\"Head\\"`)."},{"name":"player","lua_type":"Player?","desc":"Player whose character was hit, if any."},{"name":"character","lua_type":"Model","desc":"The hit character Model."},{"name":"position","lua_type":"Vector3","desc":"World-space intersection point."},{"name":"extra","lua_type":"Extra","desc":"Per-cast extra table."}],"source":{"line":158,"path":"src/init.lua"}},{"name":"DestroyedCtx","desc":"Argument to a definition\'s `onDestroyed` callback. Fired when the projectile\\nexpires (lifetime, power exhausted, or destroyed by terrain).","fields":[{"name":"type","lua_type":"string","desc":"Definition key the projectile was cast under."},{"name":"caster","lua_type":"Caster","desc":"Whoever fired the projectile."},{"name":"position","lua_type":"Vector3","desc":"World-space position when destroyed."},{"name":"extra","lua_type":"Extra","desc":"Per-cast extra table."}],"source":{"line":170,"path":"src/init.lua"}},{"name":"ProjectileDefinition","desc":"A single ammo type. Lives in the [`WorldConfig.definitionsModule`](#WorldConfig).\\nModifier values override the numeric/data fields per cast; callbacks and\\n`filter` are definition-only because functions cannot safely cross actor VM\\nboundaries.","fields":[{"name":"velocity","lua_type":"number","desc":"Initial speed in studs/second. Projectile path only."},{"name":"gravity","lua_type":"Vector3","desc":"World-space gravity vector applied every step. Projectile path only."},{"name":"lifetime","lua_type":"number","desc":"Seconds before the projectile self-destructs. Projectile path only."},{"name":"power","lua_type":"number","desc":"Penetration budget. Spent against material hardness when crossing surfaces."},{"name":"angle","lua_type":"number","desc":"Maximum impact angle (degrees) that allows a ricochet. `360` always bounces; `0` never does."},{"name":"loss","lua_type":"number","desc":"Speed lost per ricochet."},{"name":"range","lua_type":"number?","desc":"Maximum scan distance in studs for the hitscan path. Ignored by [`World:cast`](World#cast). Defaults to `1024`."},{"name":"collaterals","lua_type":"boolean?","desc":"If true, continues through players instead of stopping on the first intersection."},{"name":"raycastFilter","lua_type":"RaycastParams?","desc":"Optional `RaycastParams` overriding `World.defaultRaycastFilter`."},{"name":"filter","lua_type":"Filter?","desc":"Per-character skip predicate. Parallel-safe."},{"name":"onImpact","lua_type":"((ctx: ImpactCtx) -> ())?","desc":"World-geometry hit callback."},{"name":"onIntersection","lua_type":"((ctx: IntersectionCtx) -> ())?","desc":"Captured-character intersection callback."},{"name":"onDestroyed","lua_type":"((ctx: DestroyedCtx) -> ())?","desc":"Expiration callback. Projectile path only \u2014 never fired by [`World:hitscan`](World#hitscan)."}],"source":{"line":193,"path":"src/init.lua"}},{"name":"ProjectileModifier","desc":"Per-cast overrides for numeric / data fields only. Functions (callbacks,\\n`filter`) are not present \u2014 they live in the definitions module so each\\nactor can `require` its own copy.","fields":[{"name":"velocity","lua_type":"number?","desc":""},{"name":"gravity","lua_type":"Vector3?","desc":""},{"name":"lifetime","lua_type":"number?","desc":""},{"name":"power","lua_type":"number?","desc":""},{"name":"angle","lua_type":"number?","desc":""},{"name":"loss","lua_type":"number?","desc":""},{"name":"range","lua_type":"number?","desc":""},{"name":"collaterals","lua_type":"boolean?","desc":""},{"name":"raycastFilter","lua_type":"RaycastParams?","desc":""},{"name":"extra","lua_type":"Extra?","desc":""}],"source":{"line":212,"path":"src/init.lua"}},{"name":"CastOptions","desc":"The single argument to [`World:cast`](World#cast).","fields":[{"name":"caster","lua_type":"Caster","desc":"Whoever fired the projectile."},{"name":"type","lua_type":"string","desc":"Key in the definitions module (e.g. `\\"Bullet\\"`)."},{"name":"origin","lua_type":"Vector3","desc":"World-space spawn point."},{"name":"direction","lua_type":"Vector3","desc":"Direction of travel. Normalized internally if not unit."},{"name":"timestamp","lua_type":"number","desc":"Server time at which the projectile started. Used for rollback queries."},{"name":"visual","lua_type":"PVInstance?","desc":"Optional visual template. Cloned into `World.visualsContainer` on the client."},{"name":"modifier","lua_type":"ProjectileModifier?","desc":"Optional per-cast overrides."}],"source":{"line":226,"path":"src/init.lua"}},{"name":"CharacterPose","desc":"One character\'s frame data. The caller builds this every tick and pushes it\\nvia [`Rollback:capture`](Rollback#capture). Mismatched part counts are\\nsilently dropped at push time.","fields":[{"name":"rig","lua_type":"string","desc":"Rig key (e.g. `\\"R15\\"`, `\\"R6\\"`) \u2014 must match one in [`RollbackConfig.rigs`](#RollbackConfig)."},{"name":"rootPosition","lua_type":"Vector3","desc":"World-space position used to bucket the character into the voxel broadphase."},{"name":"parts","lua_type":"{ CFrame }","desc":"Per-part CFrames, indexed in parallel with the rig\'s `parts` list."},{"name":"player","lua_type":"Player?","desc":"Owning player, if any. Surfaces on [`RollbackHit`](#RollbackHit).player and the [`Filter`](#Filter)\'s `victim` argument."}],"source":{"line":239,"path":"src/init.lua"}},{"name":"CharacterPoses","desc":"The shape consumed by [`Rollback:capture`](Rollback#capture).","lua_type":"{ [Model]: CharacterPose }","source":{"line":246,"path":"src/init.lua"}},{"name":"RollbackHit","desc":"The shape returned by [`Rollback:queryRay`](Rollback#queryRay).","fields":[{"name":"player","lua_type":"Player?","desc":"Owning player of the character that was hit."},{"name":"character","lua_type":"Model","desc":"The hit character Model."},{"name":"part","lua_type":"string","desc":"Name of the part that was intersected (e.g. `\\"Head\\"`)."},{"name":"position","lua_type":"Vector3","desc":"World-space hit point."},{"name":"distance","lua_type":"number","desc":"Distance from the ray origin to the hit point."}],"source":{"line":258,"path":"src/init.lua"}}],"name":"Hindsight","desc":"The top-level module. Returned by `require(path.to.Hindsight)`.\\n\\nHindsight exposes one factory ([`createWorld`](#createWorld)) plus a\\n[`Defaults`](Defaults) table for introspection. Every other interaction \u2014\\ncasting projectiles, capturing rollback poses, querying snapshots \u2014 goes\\nthrough the [`World`](World) and [`Rollback`](Rollback) objects this factory\\nbuilds.\\n\\n```lua\\nlocal Hindsight = require(ReplicatedStorage.Hindsight)\\n\\nlocal world = Hindsight.createWorld({\\n    actorContainer    = ServerScriptService,\\n    definitionsModule = ReplicatedStorage.Shared.Definitions,\\n})\\n```","source":{"line":32,"path":"src/init.lua"}}')}}]);